sql = """ CREATE OR REPLACE FUNCTION pager_get_board_data(p_company_id INTEGER, p_website_id INTEGER) RETURNS JSONB AS $$ DECLARE v_active JSONB; v_resolved JSONB; v_stats JSONB; v_on_duty VARCHAR; BEGIN -- Get current on-duty user name SELECT r.name INTO v_on_duty FROM calendar_event e JOIN res_users u ON e.user_id = u.id JOIN res_partner r ON u.partner_id = r.id WHERE e.is_pager_duty = TRUE AND e.start <= NOW() AND e.stop >= NOW() AND (e.website_id = p_website_id OR (e.website_id IS NULL AND p_website_id IS NULL)) AND u.company_id = p_company_id LIMIT 1;
-- Get active incidents (capped at 50) SELECT jsonb_agg(t) INTO v_active FROM ( SELECT name, source, severity, status, create_date, (SELECT r.name FROM res_users u JOIN res_partner r ON u.partner_id = r.id WHERE u.id = i.acknowledged_by_id) as ack_name FROM pager_incident i WHERE status IN ('open', 'acknowledged') AND (website_id = p_website_id OR (website_id IS NULL AND p_website_id IS NULL)) AND company_id = p_company_id ORDER BY create_date DESC LIMIT 50 ) t;
-- Get resolved incidents (capped at 10) SELECT jsonb_agg(t) INTO v_resolved FROM ( SELECT name, source, severity, time_resolved FROM pager_incident WHERE status = 'resolved' AND (website_id = p_website_id OR (website_id IS NULL AND p_website_id IS NULL)) AND company_id = p_company_id ORDER BY time_resolved DESC LIMIT 10 ) t;
-- Get stats SELECT jsonb_object_agg(status, count) INTO v_stats FROM ( SELECT status, count(*) as count FROM pager_check WHERE (website_id = p_website_id OR (website_id IS NULL AND p_website_id IS NULL)) AND company_id = p_company_id GROUP BY status ) t;
RETURN jsonb_build_object( 'on_duty', COALESCE(v_on_duty, 'None'), 'active', COALESCE(v_active, '[]'::jsonb), 'resolved', COALESCE(v_resolved, '[]'::jsonb), 'stats', jsonb_build_object( 'passing', COALESCE((v_stats->>'passing')::int, 0), 'failing', COALESCE((v_stats->>'failing')::int, 0), 'maintenance', COALESCE((v_stats->>'maintenance')::int, 0) ) ); END; $$ LANGUAGE plpgsql; """ env.cr.execute(sql)
